1	import { useEffect, useRef } from "react";
2	import { useQuery, useMutation, useQueryClient, type QueryClient } from "@tanstack/react-query";
3	import * as api from "@/lib/api/client";
4	import type {
5	  ProbabilityEditPayload,
6	  EventTradePayload,
7	  CommentPayload,
8	  Session,
9	  MarketDetailResponse,
10	  MarketPriceMessage,
11	  MarketStatus,
12	  MarketListFilterInput,
13	} from "@/lib/api/types";
14	
15	export const queryKeys = {
16	  markets: (filters?: MarketListFilterInput) => ["markets", api.normalizeMarketListFilters(filters)] as const,
17	  market: (id: string) => ["markets", id] as const,
18	  marketEvents: (id: string) => ["markets", id, "events"] as const,
19	  marketComments: (id: string) => ["markets", id, "comments"] as const,
20	  engineStats: (id: string) => ["markets", id, "engine-stats"] as const,
21	  accountRisk: (id: string) => ["accounts", id, "risk"] as const,
22	  accountExposure: (id: string) => ["accounts", id, "exposure"] as const,
23	  health: () => ["health"] as const,
24	  serviceIndex: () => ["service-index"] as const,
25	};
26	
27	const INITIAL_RECONNECT_DELAY_MS = 500;
28	const MAX_RECONNECT_DELAY_MS = 5000;
29	
30	function invalidateMarketCollectionQueries(qc: QueryClient) {
31	  return qc.invalidateQueries({
32	    predicate: ({ queryKey }) => Array.isArray(queryKey)
33	      && queryKey[0] === "markets"
34	      && typeof queryKey[1] === "object"
35	      && queryKey[1] !== null,
36	  });
37	}
38	
39	function invalidateMarketDependentQueries(qc: QueryClient, marketId: string) {
40	  void qc.invalidateQueries({ queryKey: queryKeys.marketEvents(marketId) });
41	  void qc.invalidateQueries({ queryKey: queryKeys.engineStats(marketId) });
42	  void invalidateMarketCollectionQueries(qc);
43	}
44	
45	function invalidateAccountExposureQuery(qc: QueryClient, accountId: string) {
46	  return qc.invalidateQueries({
47	    queryKey: queryKeys.accountExposure(accountId),
48	    exact: true,
49	  });
50	}
51	
52	function invalidateAccountExposureQueries(qc: QueryClient) {
53	  return qc.invalidateQueries({
54	    predicate: ({ queryKey }) => Array.isArray(queryKey)
55	      && queryKey.length === 3
56	      && queryKey[0] === "accounts"
57	      && typeof queryKey[1] === "string"
58	      && queryKey[2] === "exposure",
59	  });
60	}
61	
62	function refetchMarketRouteQueries(qc: QueryClient, marketId: string) {
63	  void qc.invalidateQueries({ queryKey: queryKeys.market(marketId) });
64	  invalidateMarketDependentQueries(qc, marketId);
65	}
66	
67	function isMarketStatus(value: unknown): value is MarketStatus {
68	  return value === "active" || value === "resolved" || value === "closed" || value === "draft";
69	}
70	
71	function isRecord(value: unknown): value is Record<string, unknown> {
72	  return typeof value === "object" && value !== null;
73	}
74	
75	function parseMarginals(value: unknown): Record<string, number> | null {
76	  if (!isRecord(value)) {
77	    return null;
78	  }
79	
80	  const marginals: Record<string, number> = {};
81	  for (const [outcomeId, probability] of Object.entries(value)) {
82	    if (typeof probability !== "number" || !Number.isFinite(probability)) {
83	      return null;
84	    }
85	    marginals[outcomeId] = probability;
86	  }
87	  return marginals;
88	}
89	
90	function parseMarketPriceMessage(value: unknown): MarketPriceMessage | null {
91	  if (!isRecord(value)) {
92	    return null;
93	  }
94	
95	  if (
96	    typeof value.marketId !== "string"
97	    || !isMarketStatus(value.status)
98	    || typeof value.seq !== "number"
99	    || !Number.isFinite(value.seq)
100	    || typeof value.emittedAt !== "string"
101	    || typeof value.approxFlag !== "boolean"
102	  ) {
103	    return null;
104	  }
105	
106	  const marginals = parseMarginals(value.marginals);
107	  if (!marginals) {
108	    return null;
109	  }
110	
111	  let resolutionProbabilities: Record<string, number> | undefined;
112	  if (value.resolutionProbabilities != null) {
113	    const parsedResolutionProbabilities = parseMarginals(value.resolutionProbabilities);
114	    if (!parsedResolutionProbabilities) {
115	      return null;
116	    }
117	    resolutionProbabilities = parsedResolutionProbabilities;
118	  }
119	
120	  return {
121	    marketId: value.marketId,
122	    status: value.status,
123	    marginals,
124	    seq: value.seq,
125	    emittedAt: value.emittedAt,
126	    approxFlag: value.approxFlag,
127	    resolution: typeof value.resolution === "string" ? value.resolution : undefined,
128	    resolutionProbabilities,
129	  };
130	}
131	
132	export function useMarketPriceSubscription(marketId: string, opts?: { enabled?: boolean }) {
133	  const qc = useQueryClient();
134	  const enabled = opts?.enabled ?? true;
135	  const lastSeqRef = useRef<number>(-1);
136	  const reconnectAttemptRef = useRef(0);
137	  const reconnectTimerRef = useRef<number | null>(null);
138	
139	  useEffect(() => {
140	    if (!enabled || marketId.length === 0) {
141	      lastSeqRef.current = -1;
142	      reconnectAttemptRef.current = 0;
143	      if (reconnectTimerRef.current != null) {
144	        window.clearTimeout(reconnectTimerRef.current);
145	        reconnectTimerRef.current = null;
146	      }
147	      return;
148	    }
149	
150	    lastSeqRef.current = -1;
151	    reconnectAttemptRef.current = 0;
152	
153	    let socket: WebSocket | null = null;
154	    let effectClosed = false;
155	    let terminalStatus: MarketStatus | null = null;
156	
157	    const clearReconnectTimer = () => {
158	      if (reconnectTimerRef.current != null) {
159	        window.clearTimeout(reconnectTimerRef.current);
160	        reconnectTimerRef.current = null;
161	      }
162	    };
163	
164	    const scheduleReconnect = () => {
165	      clearReconnectTimer();
166	      const attempt = reconnectAttemptRef.current;
167	      const delay = Math.min(
168	        MAX_RECONNECT_DELAY_MS,
169	        INITIAL_RECONNECT_DELAY_MS * (2 ** attempt),
170	      );
171	      reconnectAttemptRef.current += 1;
172	      reconnectTimerRef.current = window.setTimeout(() => {
173	        if (effectClosed || terminalStatus !== null) {
174	          return;
175	        }
176	        refetchMarketRouteQueries(qc, marketId);
177	        connect();
178	      }, delay);
179	    };
180	
181	    const connect = () => {
182	      if (effectClosed || terminalStatus !== null) {
183	        return;
184	      }
185	
186	      socket = new WebSocket(api.getMarketPricesWebSocketUrl(marketId));
187	
188	      socket.addEventListener("open", () => {
189	        const reconnecting = reconnectAttemptRef.current > 0;
190	        reconnectAttemptRef.current = 0;
191	        clearReconnectTimer();
192	        if (reconnecting) {
193	          refetchMarketRouteQueries(qc, marketId);
194	        }
195	      });
196	
197	      socket.addEventListener("message", (event) => {
198	        if (typeof event.data !== "string") {
199	          return;
200	        }
201	
202	        let raw: unknown;
203	        try {
204	          raw = JSON.parse(event.data);
205	        } catch {
206	          return;
207	        }
208	
209	        const update = parseMarketPriceMessage(raw);
210	        if (!update || update.marketId !== marketId || update.seq <= lastSeqRef.current) {
211	          return;
212	        }
213	
214	        lastSeqRef.current = update.seq;
215	        qc.setQueryData<MarketDetailResponse>(queryKeys.market(marketId), (current) => {
216	          if (!current) {
217	            return current;
218	          }
219	
220	          return {
221	            ...current,
222	            market: {
223	              ...current.market,
224	              status: update.status,
225	              marginals: update.marginals,
226	              resolution: update.resolution ?? current.market.resolution,
227	              resolutionProbabilities: update.resolutionProbabilities ?? current.market.resolutionProbabilities,
228	            },
229	          };
230	        });
231	
232	        invalidateMarketDependentQueries(qc, marketId);
233	
234	        if (update.status !== "active") {
235	          terminalStatus = update.status;
236	          refetchMarketRouteQueries(qc, marketId);
237	          socket?.close();
238	        }
239	      });
240	
241	      socket.addEventListener("error", () => {
242	        socket?.close();
243	      });
244	
245	      socket.addEventListener("close", () => {
246	        socket = null;
247	        if (effectClosed) {
248	          return;
249	        }
250	
251	        if (terminalStatus !== null) {
252	          return;
253	        }
254	
255	        refetchMarketRouteQueries(qc, marketId);
256	        scheduleReconnect();
257	      });
258	    };
259	
260	    connect();
261	
262	    return () => {
263	      effectClosed = true;
264	      clearReconnectTimer();
265	      reconnectAttemptRef.current = 0;
266	      terminalStatus = null;
267	      socket?.close();
268	      socket = null;
269	    };
270	  }, [enabled, marketId, qc]);
271	}
