92	function serializeMarketListFilters(filters?: MarketListFilterInput): string {
93	  const normalizedFilters = normalizeMarketListFilters(filters);
94	  const params = new URLSearchParams();
95	
96	  if (normalizedFilters.status) {
97	    params.set("status", normalizedFilters.status);
98	  }
99	
100	  if (normalizedFilters.includeResolved) {
101	    params.set("include_resolved", "true");
102	  }
103	
104	  const queryString = params.toString();
105	  return queryString ? `?${queryString}` : "";
106	}
