75	export function normalizeMarketListFilters(
76	  filters?: MarketListFilterInput,
77	): NormalizedMarketListFilters {
78	  const status = typeof filters === "string"
79	    ? filters
80	    : filters?.status;
81	  const includeResolved = (
82	    typeof filters !== "string"
83	    && filters?.includeResolved === true
84	  ) || status === "resolved";
85	
86	  return {
87	    ...(status ? { status } : {}),
88	    ...(includeResolved ? { includeResolved: true } : {}),
89	  };
90	}
