export type MarketListFilterInput = MarketListFilters | string;

export interface MarketPriceMessage {
  marketId: string;
  status: MarketStatus;
  marginals: Record<string, number>;
  seq: number;
  emittedAt: string;
  approxFlag: boolean;
  resolution?: string;
  resolutionProbabilities?: Record<string, number>;
  terminalEvent?: {
    eventId?: string;
    eventType?: string;
    commandId?: string;
  };
}

